    downloadFileFromUrl: function(url, cfg) {
        cfg = cfg || {};
        var me = this;

        // Mask opcional (Modern)
        if (cfg.maskCmp && cfg.maskCmp.setMasked) {
            cfg.maskCmp.setMasked({ xtype: 'loadmask', message: cfg.maskText || 'Descargando...' });
        }

        Ext.Ajax.request({
            url   : url,
            method: 'GET',
            binary: true,
            headers: cfg.headers || undefined,

            success: function (resp) {
                if (cfg.maskCmp && cfg.maskCmp.setMasked) cfg.maskCmp.setMasked(false);

                var ct    = resp.getResponseHeader('Content-Type') || 'application/octet-stream';
                var bytes = resp.responseBytes || resp.responseArrayBuffer || null;

                if (!bytes) {
                    (me.toastAlert || Ext.toast).call(me, 'Respuesta binaria no disponible');
                    if (typeof cfg.onFail === 'function') cfg.onFail(resp);
                    return;
                }

                var blob   = new Blob([new Uint8Array(bytes)], { type: ct });
                var objUrl = (window.URL || window.webkitURL).createObjectURL(blob);

                // Intentar nombre desde Content-Disposition
                var cd   = resp.getResponseHeader('Content-Disposition') || '';
                var name = cfg.filename || 'archivo';

                var a = document.createElement('a');
                a.href = objUrl;
                a.download = name;
                document.body.appendChild(a);
                a.click();
                a.remove();

                setTimeout(function () {
                    (window.URL || window.webkitURL).revokeObjectURL(objUrl);
                }, 1500);

                // 3. Quitamos la máscara en cuanto la hoja se muestra
                Ext.Viewport.unmask();

                if (typeof cfg.onDone === 'function') cfg.onDone({ ok: true, filename: name, contentType: ct });
            },

            failure: function (resp) {
                if (cfg.maskCmp && cfg.maskCmp.setMasked) cfg.maskCmp.setMasked(false);

                if (me.toastAlert) me.toastAlert(cfg.failMsg || 'No se pudo descargar el archivo', 'error');
                else Ext.toast(cfg.failMsg || 'No se pudo descargar el archivo');

                if (typeof cfg.onFail === 'function') cfg.onFail(resp);
            }
        });
    }

